 47→function filterSections(sections: SectionData[], query: string): SectionData[] {
 48→  if (!query) return sections;
 49→  const lower = query.toLowerCase();
 50→  return sections
 51→    .map(section => ({
 52→      ...section,
 53→      items: section.items.filter(
 54→        item =>
 55→          item.title.toLowerCase().includes(lower) ||
 56→          item.subtitle?.toLowerCase().includes(lower),
 57→      ),
 58→    }))
 59→    .filter(section => section.items.length > 0);
 60→}
