 62→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 63→  if (!query) return colors;
 64→  const lower = query.toLowerCase();
 65→  return colors.filter(
 66→    c =>
 67→      c.title.toLowerCase().includes(lower) ||
 68→      c.subtitle?.toLowerCase().includes(lower),
 69→  );
 70→}
